UPDATE pms_sku_stock
SET lock_stock = lock_stock + #{quantity}
WHERE id = #{skuId}
  AND stock - lock_stock >= #{quantity}

UPDATE ums_member
SET integration = IFNULL(integration, 0) + #{delta}
WHERE id = #{memberId}
  AND IFNULL(integration, 0) + #{delta} >= 0

